:root { color-scheme: light dark; }

.body { background-color: #ffffff; margin: 0; padding: 0; }
.outer-table, .outer-td, .inner-td { background-color: #ffffff; }

.block-row__cell { padding: 0 !important; }
.block-row { padding: 0 !important; }

p {
color: #171717;
font-family: -apple-system,BlinkMacSystemFont,'Segoe
UI','Roboto','Oxygen','Ubuntu','Cantarell','Fira Sans','Droid
Sans','Helvetica Neue',sans-serif;
font-size: 16px; line-height: 1.5; margin: 0 0 16px 0;
overflow-wrap: anywhere;
}
.break-all { color: #171717; font-size: 16px; line-height: 1.5;
word-break: break-all; }
h1 {
color: #171717;
font-family: -apple-system,BlinkMacSystemFont,'Segoe
UI','Roboto','Oxygen','Ubuntu','Cantarell','Fira Sans','Droid
Sans','Helvetica Neue',sans-serif;
font-size: 24px; font-weight: 600; letter-spacing: -0.02em;
margin: 0 0 24px 0; padding: 0;
}
h2 { color: #171717; font-size: 18px; font-weight: 600; margin: 0
0 16px 0; }
h3 { color: #171717; font-size: 16px; font-weight: 600; margin: 0
0 12px 0; }
a { color: #0067D6; text-decoration: none; }
.block-markdown a { color: #0067D6; text-decoration: none; }
a.block-button { color: inherit; }
strong { color: #171717; font-weight: 600; }
pre {
font-family:
ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,'Liberation
Mono','Courier New',monospace;
color: #171717; background-color: #F2F2F2; border: 1px solid
#E6E6E6;
padding: 12px 16px; border-radius: 8px; font-size: 14px;
max-width: 100%; overflow: hidden; text-overflow: ellipsis;
}
code.inline {
font-family:
ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,'Liberation
Mono','Courier New',monospace;
color: #171717; font-size: 0.9em; background-color: #F2F2F2;
padding: 2px 6px; border-radius: 4px;
}
ul { padding-left: 20px; margin: -8px 0 16px 0; }
li { font-family: -apple-system,BlinkMacSystemFont,'Segoe
UI','Roboto','Oxygen','Ubuntu','Cantarell','Fira Sans','Droid
Sans','Helvetica Neue',sans-serif; font-size: 16px; line-height:
1.75; color: #171717; }
.footer-text { color: #7D7D7D; font-size: 14px; line-height: 1.5;
margin: 0 0 8px 0; }
.footer-text a { color: #7D7D7D !important; text-decoration:
underline !important; font-weight: 400 !important; }
.footer-link { color: #7D7D7D !important; text-decoration:
underline !important; font-weight: 400 !important; }
.footer-hr { border-top-color: #E6E6E6; }

.block-row.block-row--button_set-v1 { margin: 32px 0 !important;
}
.block-row.block-row--button_set-v1 .block-button { display:
inline-block; box-sizing: border-box; text-decoration: none;
-webkit-text-size-adjust: none; }
.block-row.block-row--button_set-v1
.block-button.block-button--solid.block-button--sm {
background-color: #000000 !important; border-radius: 8px
!important; color: #ffffff !important;
font-family: -apple-system,BlinkMacSystemFont,'Segoe
UI','Roboto','Oxygen','Ubuntu','Cantarell','Fira Sans','Droid
Sans','Helvetica Neue',sans-serif;
font-size: 16px; font-weight: 500; padding: 14px 20px;
text-align: center; text-decoration: none;
}
.block-row.block-row--button_set-v1
.block-button.block-button--outline {
border-style: solid; border-color: #E6E6E6; border-radius: 8px;
color: #171717; font-size: 16px; font-weight: 500; padding: 14px
20px;
}
.block-row.block-row--divider-v1 .block-divider { border-bottom:
1px solid #E6E6E6; }
.block-row.block-row--markdown-v1 .block-markdown > :first-child
{ margin-top: 0; }
.block-row.block-row--markdown-v1 .block-markdown > :last-child {
margin-bottom: 0; }

@media (prefers-color-scheme: dark) {
.body, .outer-table, .outer-td, .inner-td { background-color:
#111111 !important; }
p, .break-all, li, td { color: #ededed !important; }
h1, h2, h3, strong { color: #ffffff !important; }
a { color: #4da3ff !important; }
td[bgcolor="#000000"], .email-cta { background-color: #EDEDED
!important; }
td[bgcolor="#000000"] a, .email-cta a { color: #0A0A0A
!important; background-color: #EDEDED !important; }
pre { color: #ededed !important; background-color: #282828
!important; border-color: #333333 !important; }
code, code.inline { color: #ededed !important; background-color:
#282828 !important; }
.footer-text, .footer-text p { color: #7D7D7D !important; }
.footer-text a { color: #7D7D7D !important; }
.footer-link { color: #7D7D7D !important; }
.footer-hr { border-top-color: #333333 !important; }
.vercel-logo { filter: invert(1) !important; }
.block-row.block-row--button_set-v1
.block-button.block-button--solid.block-button--sm {
background-color: #EDEDED !important; color: #0A0A0A !important;
}
.block-row.block-row--button_set-v1
.block-button.block-button--outline { border-color: #333333
!important; color: #ededed !important; }
.block-row.block-row--divider-v1 .block-divider {
border-bottom-color: #333333 !important; }
.vercel-code-block { background-color: #282828 !important; color:
#ffffff !important; }
.vercel-label-default { background-color: #282828 !important;
color: #ededed !important; }
.vercel-label-info { background-color: #0A2540 !important; color:
#4da3ff !important; }
.vercel-label-error { background-color: #3D1417 !important;
color: #FF6166 !important; }
}

@media only screen and (max-width: 620px) {
.outer-td { padding: 32px 16px !important; }
}
